     1→import { stringify } from "../utils/json.js";
     2→import { withCache } from "../utils/promise/withCache.js";
     3→import { networkToCaip2ChainId, } from "./schemas.js";
     4→import { x402Version, } from "./types.js";
     5→const DEFAULT_BASE_URL = "https://api.thirdweb.com/v1/payments/x402";
     6→/**
     7→ * Creates a facilitator for the x402 payment protocol.
     8→ * You can use this with `settlePayment` or with any x402 middleware to enable settling transactions with your thirdweb server wallet.
     9→ *
    10→ * @param config - The configuration for the facilitator
    11→ * @returns a x402 compatible FacilitatorConfig
    12→ *
    13→ * @example
    14→ * ```ts
    15→ * import { facilitator } from "thirdweb/x402";
    16→ * import { createThirdwebClient } from "thirdweb";
    17→ * import { paymentMiddleware } from 'x402-hono'
    18→ *
    19→ * const client = createThirdwebClient({
    20→ *   secretKey: "your-secret-key",
    21→ * });
    22→ * const thirdwebX402Facilitator = facilitator({
    23→ *   client: client,
    24→ *   serverWalletAddress: "0x1234567890123456789012345678901234567890",
    25→ * });
    26→ *
    27→ * // add the facilitator to any x402 payment middleware
    28→ * const middleware = paymentMiddleware(
    29→ *   "0x1234567890123456789012345678901234567890",
    30→ *   {
    31→ *     "/api/paywall": {
    32→ *       price: "$0.01",
    33→ *       network: "base-sepolia",
    34→ *       config: {
    35→ *         description: "Access to paid content",
    36→ *       },
    37→ *     },
    38→ *   },
    39→ *   thirdwebX402Facilitator,
    40→ * );
    41→ * ```
    42→ *
    43→ * #### Configuration Options
    44→ *
    45→ * ```ts
    46→ * const thirdwebX402Facilitator = facilitator({
    47→ *   client: client,
    48→ *   serverWalletAddress: "0x1234567890123456789012345678901234567890",
    49→ *   // Optional: Wait behavior for settlements
    50→ *   // - "simulated": Only simulate the transaction (fastest)
    51→ *   // - "submitted": Wait until transaction is submitted
    52→ *   // - "confirmed": Wait for full on-chain confirmation (slowest, default)
    53→ *   waitUntil: "confirmed",
    54→ * });
    55→
    56→ * ```
    57→ *
    58→ * @x402
    59→ */
    60→export function facilitator(config) {
    61→    const secretKey = config.client.secretKey;
    62→    if (!secretKey) {
    63→        throw new Error("Client secret key is required for the x402 facilitator");
    64→    }
    65→    const serverWalletAddress = config.serverWalletAddress;
    66→    if (!serverWalletAddress) {
    67→        throw new Error("Server wallet address is required for the x402 facilitator");
    68→    }
    69→    const facilitator = {
    70→        url: (config.baseUrl ?? DEFAULT_BASE_URL),
    71→        address: serverWalletAddress,
    72→        createAuthHeaders: async () => {
    73→            return {
    74→                verify: {
    75→                    "x-secret-key": secretKey,
    76→                },
    77→                settle: {
    78→                    "x-secret-key": secretKey,
    79→                    ...(config.vaultAccessToken
    80→                        ? { "x-vault-access-token": config.vaultAccessToken }
    81→                        : {}),
    82→                },
    83→                supported: {
    84→                    "x-secret-key": secretKey,
    85→                },
    86→                list: {
    87→                    "x-secret-key": secretKey,
    88→                },
    89→            };
    90→        },
    91→        /**
    92→         * Verifies a payment payload with the facilitator service
    93→         *
    94→         * @param payload - The payment payload to verify
    95→         * @param paymentRequirements - The payment requirements to verify against
    96→         * @returns A promise that resolves to the verification response
    97→         */
    98→        async verify(payload, paymentRequirements) {
    99→            const url = config.baseUrl ?? DEFAULT_BASE_URL;
   100→            let headers = { "Content-Type": "application/json" };
   101→            const authHeaders = await facilitator.createAuthHeaders();
   102→            headers = { ...headers, ...authHeaders.verify };
   103→            const res = await fetch(`${url}/verify`, {
   104→                method: "POST",
   105→                headers,
   106→                body: stringify({
   107→                    x402Version: payload.x402Version,
   108→                    paymentPayload: payload,
   109→                    paymentRequirements: paymentRequirements,
   110→                }),
   111→            });
   112→            if (res.status !== 200) {
   113→                const text = `${res.statusText} ${await res.text()}`;
   114→                throw new Error(`Failed to verify payment: ${res.status} ${text}`);
   115→            }
   116→            const data = await res.json();
   117→            return data;
   118→        },
   119→        /**
   120→         * Settles a payment with the facilitator service
   121→         *
   122→         * @param payload - The payment payload to settle
   123→         * @param paymentRequirements - The payment requirements for the settlement
   124→         * @returns A promise that resolves to the settlement response
   125→         */
   126→        async settle(payload, paymentRequirements, waitUntil) {
   127→            const url = config.baseUrl ?? DEFAULT_BASE_URL;
   128→            let headers = { "Content-Type": "application/json" };
   129→            const authHeaders = await facilitator.createAuthHeaders();
   130→            headers = { ...headers, ...authHeaders.settle };
   131→            const waitUntilParam = waitUntil || config.waitUntil;
   132→            const res = await fetch(`${url}/settle`, {
   133→                method: "POST",
   134→                headers,
   135→                body: JSON.stringify({
   136→                    x402Version: payload.x402Version,
   137→                    paymentPayload: payload,
   138→                    paymentRequirements: paymentRequirements,
   139→                    ...(waitUntilParam ? { waitUntil: waitUntilParam } : {}),
   140→                }),
   141→            });
   142→            if (res.status !== 200) {
   143→                const text = `${res.statusText} ${await res.text()}`;
   144→                throw new Error(`Failed to settle payment: ${res.status} ${text}`);
   145→            }
   146→            const data = await res.json();
   147→            return data;
   148→        },
   149→        /**
   150→         * Gets the supported payment kinds from the facilitator service.
   151→         *
   152→         * @returns A promise that resolves to the supported payment kinds
   153→         */
   154→        async supported(filters) {
   155→            const url = config.baseUrl ?? DEFAULT_BASE_URL;
   156→            return withCache(async () => {
   157→                let headers = { "Content-Type": "application/json" };
   158→                const authHeaders = await facilitator.createAuthHeaders();
   159→                headers = { ...headers, ...authHeaders.supported };
   160→                const supportedUrl = new URL(`${url}/supported`);
   161→                if (filters?.chainId) {
   162→                    supportedUrl.searchParams.set("chainId", filters.chainId.toString());
   163→                }
   164→                if (filters?.tokenAddress) {
   165→                    supportedUrl.searchParams.set("tokenAddress", filters.tokenAddress);
   166→                }
   167→                const res = await fetch(supportedUrl.toString(), { headers });
   168→                if (res.status !== 200) {
   169→                    throw new Error(`Failed to get supported payment kinds: ${res.statusText}`);
   170→                }
   171→                const data = await res.json();
   172→                return data;
   173→            }, {
   174→                cacheKey: `supported-payment-kinds-${url}-${filters?.chainId}-${filters?.tokenAddress}2`,
   175→                cacheTime: 1000 * 60 * 60 * 1, // 1 hour
   176→            });
   177→        },
   178→        async accepts(args) {
   179→            const url = config.baseUrl ?? DEFAULT_BASE_URL;
   180→            let headers = { "Content-Type": "application/json" };
   181→            const authHeaders = await facilitator.createAuthHeaders();
